<script setup lang="ts">
import AuthenticatedLayout from '@/Layouts/AuthenticatedLayout.vue'; import { Head, Link } from '@inertiajs/vue3';
const props = defineProps<{ attendance:{id:number;work_date:string;check_in:string|null;check_out:string|null;worked_minutes:number;late_minutes:number;overtime_minutes:number;employee:{first_name:string;last_name:string;employee_code:string}} }>();
